package main

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

func main() {
	// Set environment variables for insecure development setup
	os.Setenv("GOPRIVATE", "*")
	os.Setenv("GOSUMDB", "off")

	// Get the current working directory
	wd, err := os.Getwd()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error getting working directory: %v\n", err)
		os.Exit(1)
	}

	// Check if go.mod exists
	goModPath := filepath.Join(wd, "go.mod")
	if _, err := os.Stat(goModPath); os.IsNotExist(err) {
		fmt.Fprintf(os.Stderr, "go.mod not found in %s\n", wd)
		os.Exit(1)
	}

	// Run go mod tidy to fetch dependencies
	fmt.Println("Fetching dependencies...")
	cmd := exec.Command("go", "mod", "tidy")
	cmd.Dir = wd
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		fmt.Fprintf(os.Stderr, "Error running go mod tidy: %v\n", err)
		os.Exit(1)
	}

	// Get additional packages with insecure flag for internal repos
	packages := []string{
		"github.com/yourcompany/yourinternalpackage",
		"github.com/anotherinternal/package",
	}

	for _, pkg := range packages {
		if strings.Contains(pkg, "internal") || strings.Contains(pkg, "company") {
			fmt.Printf("Fetching insecure package: %s\n", pkg)
			cmd := exec.Command("go", "get", "-insecure", pkg)
			cmd.Dir = wd
			cmd.Stdout = os.Stdout
			cmd.Stderr = os.Stderr
			if err := cmd.Run(); err != nil {
				fmt.Fprintf(os.Stderr, "Error fetching insecure package %s: %v\n", pkg, err)
				os.Exit(1)
			}
		} else {
			fmt.Printf("Fetching package: %s\n", pkg)
			cmd := exec.Command("go", "get", pkg)
			cmd.Dir = wd
			cmd.Stdout = os.Stdout
			cmd.Stderr = os.Stderr
			if err := cmd.Run(); err != nil {
				fmt.Fprintf(os.Stderr, "Error fetching package %s: %v\n", pkg, err)
				os.Exit(1)
			}
		}
	}

	fmt.Println("Dependencies fetched successfully.")
}